import asyncio
import logging
import time

import torch

from rllm_train.hf_engine import HFAgentExecutionEngine
from rllm_train.math_env import MathCalcEnv

logger = logging.getLogger(__name__)


def make_rllm_rollout_func(
    agent_class,
    agent_args=None,
    env_class=None,
    env_args=None,
    max_steps=3,
    max_response_length=256,
    max_prompt_length=512,
    sampling_params=None,
    training_logger=None,
    trajectory_writer=None,
    perf_tracker=None,
    answer_map=None,
):
    if agent_args is None:
        agent_args = {}
    if env_args is None:
        env_args = {}
    if env_class is None:
        env_class = MathCalcEnv
    if sampling_params is None:
        sampling_params = {"temperature": 0.7, "top_p": 0.9}
    if answer_map is None:
        answer_map = {}

    _step_counter = [0]

    def rollout_func(prompts, trainer):
        _step_counter[0] += 1
        step = _step_counter[0]
        model = trainer.model
        tokenizer = trainer.processing_class
        device = trainer.accelerator.device

        num_gens = getattr(trainer.args, "num_generations", len(prompts))
        if training_logger:
            training_logger.log_rollout_start(step, len(prompts), num_gens)
        if perf_tracker:
            perf_tracker.start_rollout(step)

        model.eval()

        engine = HFAgentExecutionEngine(
            model=model,
            tokenizer=tokenizer,
            n_parallel_agents=len(prompts),
            max_steps=max_steps,
            max_response_length=max_response_length,
            max_prompt_length=max_prompt_length,
            agent_class=agent_class,
            agent_args=agent_args,
            env_class=env_class,
            env_args=env_args,
            sampling_params=sampling_params,
            on_trajectory_done=lambda idx, total, reward: (
                training_logger.log_trajectory_done(step, idx, total, reward)
                if training_logger else None
            ),
        )

        envs = []
        agents = []
        for prompt in prompts:
            task = _extract_task_from_prompt(prompt)
            if task["question"] in answer_map:
                task["answer"] = answer_map[task["question"]]
            task.update(env_args)
            env = env_class.from_dict(task)
            agent = agent_class(**agent_args)
            envs.append(env)
            agents.append(agent)

        engine.update_envs_and_agents(envs, agents)

        try:
            loop = asyncio.get_event_loop()
            if loop.is_running():
                import concurrent.futures
                with concurrent.futures.ThreadPoolExecutor() as pool:
                    results = pool.submit(
                        lambda: asyncio.run(engine.run_trajectories(mode="Token"))
                    ).result()
            else:
                results = loop.run_until_complete(engine.run_trajectories(mode="Token"))
        except RuntimeError:
            results = asyncio.run(engine.run_trajectories(mode="Token"))

        model.train()

        # Perf tracking: end rollout phase
        rollout_stats = None
        if perf_tracker:
            rollout_stats = perf_tracker.end_rollout(results)

        # Write trajectories to file
        if trajectory_writer:
            trajectory_writer.write_rollout(step, agents, envs, results, tokenizer)

        prompt_ids_list = []
        completion_ids_list = []
        env_mask_list = []

        for result in results:
            prompt_ids_list.append(result["prompt_tokens"].tolist())
            completion_ids_list.append(result["response_tokens"].tolist())
            env_mask_list.append(result["response_masks"].tolist())

        rewards = [r.get("trajectory_reward", 0.0) if isinstance(r, dict) else 0.0 for r in results]
        if training_logger:
            training_logger.log_rollout_done(step, len(results), rewards, rollout_stats=rollout_stats)

        # Compute logprobs with timing
        if training_logger:
            training_logger.log_logprob_start(step)
        if perf_tracker:
            perf_tracker.start_logprob_compute()

        logprobs_list = _compute_logprobs(
            model, tokenizer, prompt_ids_list, completion_ids_list, device
        )

        if perf_tracker:
            perf_tracker.end_logprob_compute()

        if training_logger:
            training_logger.log_training_update_start(step)

        return {
            "prompt_ids": prompt_ids_list,
            "completion_ids": completion_ids_list,
            "logprobs": logprobs_list,
            "env_mask": env_mask_list,
        }

    return rollout_func


def _extract_task_from_prompt(prompt):
    if isinstance(prompt, list):
        for msg in prompt:
            if isinstance(msg, dict) and msg.get("role") == "user":
                return {"question": msg["content"]}
        return {"question": str(prompt)}
    return {"question": str(prompt)}


def _compute_logprobs(model, tokenizer, prompt_ids_list, completion_ids_list, device):
    logprobs_list = []
    for prompt_ids, completion_ids in zip(prompt_ids_list, completion_ids_list):
        if not completion_ids:
            logprobs_list.append([])
            continue
        input_ids = torch.tensor([prompt_ids + completion_ids], device=device)
        with torch.no_grad():
            outputs = model(input_ids)
            logits = outputs.logits
        prompt_len = len(prompt_ids)
        completion_logits = logits[0, prompt_len - 1:-1, :]
        completion_tokens = torch.tensor(completion_ids, device=device)
        log_probs = torch.log_softmax(completion_logits, dim=-1)
        token_logprobs = log_probs.gather(1, completion_tokens.unsqueeze(1)).squeeze(1)
        logprobs_list.append(token_logprobs.cpu().tolist())
    return logprobs_list

"""
Self-contained chat template and tool parsers inlined from rllm.
Provides QwenChatTemplateParser, QwenToolParser, and helper functions
for converting messages to tokens and masks.
"""

import json
from typing import Any

from rllm_train.base import ToolCall


class ChatTemplateParser:
    def __init__(self, tokenizer):
        self.tokenizer = tokenizer
        self.assistant_token = ""

    def parse(self, messages, add_generation_prompt=False, is_first_msg=False, **kwargs) -> str:
        return self.tokenizer.apply_chat_template(
            messages, tokenize=False, add_generation_prompt=add_generation_prompt
        )

    @classmethod
    def get_parser(cls, tokenizer, disable_thinking=False) -> "ChatTemplateParser":
        if isinstance(tokenizer.name_or_path, str):
            model_name = tokenizer.name_or_path.lower()
            tokenizer_cls = tokenizer.__class__.__name__.lower()
            if "qwen" in model_name or "qwen" in tokenizer_cls:
                return QwenChatTemplateParser(tokenizer, disable_thinking=disable_thinking)
        return ChatTemplateParser(tokenizer)


class QwenChatTemplateParser(ChatTemplateParser):
    def __init__(self, tokenizer, disable_thinking=True):
        super().__init__(tokenizer)
        self.bos_token = tokenizer.bos_token
        self.eos_token = tokenizer.eos_token
        self.eot_token = "<|im_end|>\n"
        self.system_token = "<|im_start|>system\n"
        self.user_token = "<|im_start|>user\n"
        self.assistant_token = "<|im_start|>assistant\n"
        if disable_thinking:
            self.assistant_token += "<think>\\n\\n</think>\\n\\n"
        self.generation_prompt = self.assistant_token
        self.tool_start_token = "\n<tool_call>\n"
        self.tool_end_token = "\n</tool_call>"
        self.tool_response_start_token = "<tool_response>\n"
        self.tool_response_end_token = "\n</tool_response>"

    def parse(self, messages, add_generation_prompt=False, is_first_msg=False, **kwargs) -> str:
        result = ""
        if is_first_msg and messages[0]["role"] != "system":
            result += self.system_token + "You are Qwen, created by Alibaba Cloud. You are a helpful assistant." + self.eot_token
        for message in messages:
            role = message["role"]
            if role == "system":
                result += self.system_token + message["content"] + self.eot_token
            elif role == "user":
                result += self.user_token + message["content"] + self.eot_token
            elif role == "assistant":
                result += self.assistant_token + message["content"] + self.eot_token
            elif role == "tool":
                result += self.user_token + self.tool_response_start_token + message["content"] + self.tool_response_end_token + self.eot_token
        if add_generation_prompt:
            result += self.generation_prompt
        return result


class QwenToolParser:
    def __init__(self):
        self.tool_call_begin = "<tool_call>"
        self.tool_call_end = "</tool_call>"

    def parse(self, model_response: str) -> list[ToolCall]:
        tool_calls_dicts = self._parse_tool_calls(model_response)
        return [ToolCall(name=tc["name"], arguments=tc["arguments"]) for tc in tool_calls_dicts]

    def _parse_tool_calls(self, text: str) -> list[dict[str, Any]]:
        tool_calls: list[dict[str, Any]] = []
        if self.tool_call_begin not in text:
            return tool_calls
        while self.tool_call_begin in text:
            start = text.find(self.tool_call_begin) + len(self.tool_call_begin)
            end = text.find(self.tool_call_end)
            if end == -1:
                break
            json_content = text[start:end].strip()
            try:
                call_data = json.loads(json_content)
                tool_calls.append({"name": call_data["name"], "arguments": call_data["arguments"]})
            except json.JSONDecodeError:
                text = text[end + len(self.tool_call_end):]
                continue
            text = text[end + len(self.tool_call_end):]
        return tool_calls

    def get_tool_prompt(self, tools_schema: str) -> str:
        return f"""
You are provided with function signatures within <tools></tools> XML tags:
<tools>
{tools_schema}
</tools>

For each function call, return a json object with function name and arguments within <tool_call></tool_call> XML tags:
<tool_call>
{{"name": <function-name>, "arguments": <args-json-object>}}
</tool_call><|im_end|>
"""


def get_recent_assistant_user_messages(chat_completions_messages):
    env_messages = []
    assistant_message = None
    seen_assistant_message = False
    for message in reversed(chat_completions_messages):
        role = message.get("role", None)
        if role == "assistant":
            if assistant_message:
                break
            seen_assistant_message = True
            assistant_message = message
        elif role in ["user", "tool"] and not seen_assistant_message:
            env_messages.append(message)
    env_messages = list(reversed(env_messages))
    return assistant_message, env_messages


def convert_messages_to_tokens_and_masks(messages, tokenizer, parser, contains_first_msg=False, contains_generation_msg=False):
    all_msg_tokens = []
    all_msg_masks = []

    def _convert(msg, first_msg=False, generation_msg=False):
        msg_text = parser.parse([msg], add_generation_prompt=generation_msg, is_first_msg=first_msg)
        if msg["role"] == "assistant" and msg_text.startswith(parser.assistant_token):
            msg_text = msg_text.replace(parser.assistant_token, "", 1)
        msg_tokens = tokenizer.encode(msg_text, add_special_tokens=False)
        mask_value = 1 if msg["role"] == "assistant" else 0
        return msg_tokens, [mask_value] * len(msg_tokens)

    for i, msg in enumerate(messages):
        tokens, mask = _convert(
            msg,
            first_msg=(contains_first_msg and i == 0),
            generation_msg=(contains_generation_msg and i == len(messages) - 1),
        )
        all_msg_tokens.extend(tokens)
        all_msg_masks.extend(mask)

    return all_msg_tokens, all_msg_masks

import re


def math_reward_fn(prompts, completions, **kwargs):
    """TRL-compatible reward function for math problems.

    Extracts the final number from the completion and compares to the ground truth
    answer stored in the dataset's 'answer' field.
    """
    rewards = []
    for prompt, completion in zip(prompts, completions):
        answer = None
        if isinstance(prompt, list):
            for msg in prompt:
                if isinstance(msg, dict) and msg.get("role") == "user":
                    content = msg.get("content", "")
                    break
            else:
                content = ""
        else:
            content = str(prompt)

        gt_answer = kwargs.get("answer", [None])[0] if "answer" in kwargs else None

        if isinstance(completion, list):
            completion_text = ""
            for msg in completion:
                if isinstance(msg, dict):
                    completion_text += msg.get("content", "")
        else:
            completion_text = str(completion)

        numbers = re.findall(r'-?\d+\.?\d*', completion_text)
        if numbers and gt_answer is not None:
            try:
                predicted = float(numbers[-1])
                expected = float(gt_answer)
                rewards.append(1.0 if abs(predicted - expected) < 1e-6 else 0.0)
            except (ValueError, TypeError):
                rewards.append(0.0)
        else:
            rewards.append(0.0)

    return rewards

"""
Self-contained base abstractions inlined from rllm.
Provides BaseAgent, BaseEnv, Action, Step, Trajectory, ToolCall, ToolOutput.
"""

import json
from abc import ABC, abstractmethod
from dataclasses import asdict, dataclass, field
from typing import Any


@dataclass
class Step:
    chat_completions: list[dict[str, str]] = field(default_factory=list)
    thought: str = ""
    action: Any = None
    observation: Any = None
    model_response: str = ""
    info: dict = field(default_factory=dict)
    reward: float = 0.0
    done: bool = False
    mc_return: float = 0.0


@dataclass
class Action:
    action: Any = None


@dataclass
class Trajectory:
    task: Any = None
    steps: list[Step] = field(default_factory=list)
    reward: float = 0.0

    def to_dict(self):
        return {
            "steps": [asdict(step) for step in self.steps],
            "reward": float(self.reward),
        }


class BaseAgent(ABC):
    @property
    def chat_completions(self) -> list[dict[str, str]]:
        return []

    @property
    def trajectory(self) -> Trajectory:
        return Trajectory()

    @abstractmethod
    def update_from_env(self, observation: Any, reward: float, done: bool, info: dict, **kwargs):
        raise NotImplementedError

    @abstractmethod
    def update_from_model(self, response: str, **kwargs) -> Action:
        raise NotImplementedError

    @abstractmethod
    def reset(self):
        return

    def get_current_state(self) -> Step | None:
        if not self.trajectory.steps:
            return None
        return self.trajectory.steps[-1]


class BaseEnv(ABC):
    @property
    def idx(self) -> Any:
        return getattr(self, "_idx", None)

    @idx.setter
    def idx(self, value: Any):
        self._idx = value

    @abstractmethod
    def reset(self) -> tuple[dict, dict]:
        pass

    @abstractmethod
    def step(self, action: Any) -> tuple[Any, float, bool, dict]:
        pass

    def close(self):
        return

    @staticmethod
    @abstractmethod
    def from_dict(info: dict) -> "BaseEnv":
        raise NotImplementedError

    @staticmethod
    def is_multithread_safe() -> bool:
        return True


@dataclass
class ToolCall:
    name: str
    arguments: dict[str, Any]

    def to_dict(self):
        return {"name": self.name, "arguments": self.arguments}


@dataclass
class ToolOutput:
    name: str = ""
    output: str | list | dict | None = None
    error: str | None = None
    metadata: dict | None = None

    def __str__(self) -> str:
        if self.error:
            return f"Error: {self.error}"
        elif self.output is None:
            return ""
        elif isinstance(self.output, (list, dict)):
            return json.dumps(self.output)
        else:
            return str(self.output)

"""
Self-contained ToolAgent inlined from rllm.
"""

import copy
import json
import logging
import uuid
from typing import Any

from rllm_train.base import Action, BaseAgent, Step, Trajectory
from rllm_train.parsers import QwenToolParser

logger = logging.getLogger(__name__)


class ToolAgent(BaseAgent):
    def __init__(self, system_prompt="", parser_name="qwen", tool_map=None):
        self.system_prompt = system_prompt
        self.tool_parser = QwenToolParser()

        if tool_map is not None:
            self._tool_instances = {}
            for name, tool_cls in tool_map.items():
                self._tool_instances[name] = tool_cls()
            tools_json = [inst.json for inst in self._tool_instances.values()]
        else:
            self._tool_instances = {}
            tools_json = []

        self.tools_prompt = self.tool_parser.get_tool_prompt(json.dumps(tools_json, indent=2))
        self._trajectory = Trajectory()
        self.messages: list[dict[str, Any]] = []
        self.current_observation = None
        self.reset()

    def _format_observation_as_messages(self, obs: Any) -> list[dict]:
        messages = []
        if isinstance(obs, dict):
            if "question" in obs:
                messages.append({"role": "user", "content": obs["question"]})
            elif "tool_outputs" in obs:
                for tool_call_id, tool_output_str in obs["tool_outputs"].items():
                    messages.append({
                        "role": "tool",
                        "content": tool_output_str,
                        "tool_call_id": tool_call_id,
                    })
        elif isinstance(obs, str):
            messages.append({"role": "user", "content": obs})
        elif obs:
            messages.append({"role": "user", "content": str(obs)})
        return messages

    def update_from_env(self, observation: Any, reward: float, done: bool, info: dict, **kwargs):
        obs_messages = self._format_observation_as_messages(observation)
        self.messages.extend(obs_messages)
        self.current_observation = observation

    def update_from_model(self, response: str, **kwargs) -> Action:
        tool_calls_dict = []
        assistant_content = response
        try:
            tool_calls = self.tool_parser.parse(response)
            tool_calls_dict = [
                {
                    "id": str(uuid.uuid4()),
                    "type": "function",
                    "function": tool_call.to_dict(),
                }
                for tool_call in tool_calls
            ]
        except Exception as e:
            logger.error(f"Failed to parse tool calls: {e}")
            tool_calls_dict = []

        assistant_message = {"role": "assistant", "content": assistant_content}
        if tool_calls_dict:
            for call in tool_calls_dict:
                if isinstance(call.get("function", {}).get("arguments"), dict):
                    call["function"]["arguments"] = json.dumps(call["function"]["arguments"])
        else:
            tool_calls_dict = [
                {
                    "id": str(uuid.uuid4()),
                    "type": "function",
                    "function": {
                        "name": "finish",
                        "arguments": {"response": assistant_content},
                    },
                }
            ]

        self.messages.append(assistant_message)
        new_step = Step(
            chat_completions=copy.deepcopy(self.chat_completions),
            action=tool_calls_dict,
            model_response=response,
            observation=self.current_observation,
        )
        self._trajectory.steps.append(new_step)
        return Action(action=tool_calls_dict)

    def reset(self):
        self._trajectory = Trajectory()
        self.messages = [{"role": "system", "content": self.system_prompt + self.tools_prompt}]

    @property
    def chat_completions(self) -> list[dict[str, str]]:
        return self.messages

    @property
    def trajectory(self) -> Trajectory:
        return self._trajectory

